import { FaAngleDown } from "react-icons/fa";
import Button from "@mui/material/Button";
import { FaMapMarkerAlt } from "react-icons/fa";
import Dialog from "@mui/material/Dialog";
import { IoSearch } from "react-icons/io5";
import { MdClose } from "react-icons/md";
import React, { useContext, useEffect, useState } from "react";
import Slide from "@mui/material/Slide";
// import { MyContext } from "../../App";

const Transition = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="up" ref={ref} {...props} />;
});

const CountryDropdown = () => {
  const [isOpenModal, setisOpenModal] = useState(false);
  const [selectedTab, setselectedTab] = useState(null);
  const [countryList, setcountryList] = useState([]);

  const context = useContext(MyContext);
  const selectCountry = (index, country) => {
    setselectedTab(index);
    setisOpenModal(false);
    context.setselectedCountry(country);
  };
  // useEffect(() => {
  //   setcountryList(context.countryList);
  // }, []);
  const FilterList = (e) => {
    const keyword = e.target.value.toLowerCase();
    if (keyword !== "") {
      const list = countryList.filter((item) => {
        return item.country.toLowerCase().includes(keyword);
      });
      setcountryList(list);
    } else {
      setcountryList(context.countryList);
    }
  };
  return (
    <>
      <Button className="countryDropdown" onClick={() => setisOpenModal(true)}>
        <span className=" map">
          <FaMapMarkerAlt />
        </span>
        <div className="info d-flex flex-column">
          <span className="label"> Xem giá tại:</span>
          <span className="name">
            {context.selectedCountry !== ""
              ? context.selectedCountry.length > 10
                ? context.selectedCountry?.substr(0, 7) + "..."
                : context.selectedCountry
              : "Chọn địa chỉ "}
          </span>
        </div>
        <span className=" drop">
          <FaAngleDown />
        </span>
      </Button>
      <Dialog
        open={isOpenModal}
        onClose={() => setisOpenModal(false)}
        className="locationModal"
        TransitionComponent={Transition}
      >
        <h4 className="mb-0">Chọn vị trí của bạn</h4>
        <p>Để biết số lượng hàng tồn kho và khuyến mãi</p>
        <Button className="close_" onClick={() => setisOpenModal(false)}>
          <MdClose />
        </Button>
        <div className="headerSearch w-100">
          <input
            type="text"
            placeholder=" Tìm kiếm vị trí cuả bạn"
            onChange={FilterList}
          />
          <Button>
            <IoSearch />
          </Button>{" "}
        </div>
        <ul className="countryList mt-3">
          {countryList?.length !== 0 &&
            countryList?.map((item, index) => {
              return (
                <li key={index}>
                  <Button
                    onClick={() => selectCountry(index, item.country)}
                    className={`${selectedTab === index ? "active" : ""}`}
                  >
                    {item.country}
                  </Button>
                </li>
              );
            })}
        </ul>
      </Dialog>
    </>
  );
};
export default CountryDropdown;
